Function color_calibration(x_t, ˆx_t, x_0^visual):
    x_pred ← (x_t - √(1-α_t)·ε_θ(ˆx_t)) / √α_t ; // predicted x_0
    ... 
    ˆx_pred ← adain(x_pred, x_0^visual); // calibrated predicted x_0
Function adain(x, x^visual):
    μ_x, σ_x ← channel_wise_mean_std(x);
    μ_x^visual, σ_x^visual ← channel_wise_mean_std(x^visual);
    x_norm ← (x - μ_x) / σ_x;
    x_adain ← σ_x^visual · x_norm + μ_x^visual; // scale and shift
